import{a as e,i as t,r as n,t as r}from"./app-CnBAqX6l.js";var i=JSON.parse(`{"path":"/2026%E6%B1%9F%E8%8B%8F%E4%BB%A3%E8%A1%A8%E5%9B%A2%E5%8F%91%E8%A8%80%E6%B1%87%E6%80%BB.html","title":"2026年十四届全国人大四次会议江苏代表团发言汇总","lang":"zh-CN","frontmatter":{},"git":{"updatedTime":1774836273000,"contributors":[{"name":"JiraiyaChen","username":"JiraiyaChen","email":"979526234@qq.com","commits":1,"url":"https://github.com/JiraiyaChen"}],"changelog":[{"hash":"7318efb2b3433787199988c8a1b814510fda6eb4","time":1774836273000,"email":"979526234@qq.com","author":"JiraiyaChen","message":"Add politics/时政 docs"}]},"filePathRelative":"2026江苏代表团发言汇总.md"}`),a={name:`2026江苏代表团发言汇总.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="_2026年十四届全国人大四次会议江苏代表团发言汇总" tabindex="-1"><a class="header-anchor" href="#_2026年十四届全国人大四次会议江苏代表团发言汇总"><span>2026年十四届全国人大四次会议江苏代表团发言汇总</span></a></h1><h2 id="习近平总书记参加江苏代表团审议" tabindex="-1"><a class="header-anchor" href="#习近平总书记参加江苏代表团审议"><span>习近平总书记参加江苏代表团审议</span></a></h2><ul><li>时间：3月6日</li><li>要点：习近平参加江苏代表团审议，强调江苏等经济大省要在研究新情况、解决新问题上下功夫、出经验</li></ul><h2 id="代表发言要点" tabindex="-1"><a class="header-anchor" href="#代表发言要点"><span>代表发言要点</span></a></h2><h3 id="_1-主题发言-6位代表" tabindex="-1"><a class="header-anchor" href="#_1-主题发言-6位代表"><span>1. 主题发言（6位代表）</span></a></h3><p>史志军、张晓宏、石磊、杨恒俊、高德荣、张雨霏等6位代表分别围绕以下主题发言：</p><ul><li>推进新型工业化</li><li>促进科技创新与产业创新融合</li><li>加强关键核心技术攻关</li><li>建设和美乡村</li><li>破解种业难题</li><li>发扬体育精神</li></ul><h3 id="_2-郑海涛-扬州市市长、wcco主席" tabindex="-1"><a class="header-anchor" href="#_2-郑海涛-扬州市市长、wcco主席"><span>2. 郑海涛（扬州市市长、WCCO主席）</span></a></h3><ul><li>主题：做强实体经济，做优名城品质，扎实推进高质量发展</li></ul><h3 id="_3-吴新明-南通市委书记" tabindex="-1"><a class="header-anchor" href="#_3-吴新明-南通市委书记"><span>3. 吴新明（南通市委书记）</span></a></h3><ul><li>主题：学习习近平总书记重要讲话精神，高屋建瓴、论述精辟，为中国式现代化江苏新实践定向领航</li></ul><h3 id="_4-信长星-省委书记" tabindex="-1"><a class="header-anchor" href="#_4-信长星-省委书记"><span>4. 信长星（省委书记）</span></a></h3><ul><li>主题：完全赞同政府工作报告，就抓好&quot;十五五&quot;经济社会发展提出要求</li></ul><h3 id="_5-其他代表发言" tabindex="-1"><a class="header-anchor" href="#_5-其他代表发言"><span>5. 其他代表发言</span></a></h3><p>刘小涛、张忠、储永宏、马欣、胡广杰、樊金龙、陈忠伟、王剑锋、张国梁、邢青松等代表也先后发言</p><hr><p><em>来源：2026年十四届全国人大四次会议江苏代表团全体会议</em></p>`,17)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};